import { configureStore } from '@reduxjs/toolkit'

import userSlice, { setCurrentUser } from './user/user.slice';


export const store = configureStore({
    reducer: {
        user: setCurrentUser,
    },
})

//    ,applyMiddleware(...middlewares)
